const body = ($('Webhook').first().json.body) || {};
if (!body.project_id) return [{ json: { valid:false, error:'project_id obligatorio' } }];
return [{ json: { valid:true, project_id: body.project_id } }];

// Generador IFC4 minimalista. NO es un IFC topologico completo;
// es una representacion estructural de proyecto + site + building + storey + spaces + materials.
// Suficiente para que Revit/ArchiCAD reconozcan el proyecto y sus estancias.
const data = $input.first().json.data;
const now = new Date();
const pad = n => String(n).padStart(2,'0');
const isoStamp = `${now.getUTCFullYear()}-${pad(now.getUTCMonth()+1)}-${pad(now.getUTCDate())}T${pad(now.getUTCHours())}:${pad(now.getUTCMinutes())}:${pad(now.getUTCSeconds())}`;
const escape = s => (s || '').toString().replace(/[\\']/g, '').replace(/[^\x20-\x7E]/g, c => '\\X2\\' + c.charCodeAt(0).toString(16).toUpperCase().padStart(4,'0') + '\\X0\\');

const projectName = escape(data.project_name) || 'Project';
const location = escape((data.location_address||'') + ', ' + (data.location_city||'') + ' (' + (data.location_province||'') + ')');
const designTitle = escape(data.design_option?.title || 'Design v1');
const rooms = (data.briefing?.rooms_affected || []).map(r => typeof r === 'string' ? r : (r.room || r.name || 'Espacio'));
const materials = data.materials || [];

let line = 1;
const entities = [];
const ref = (id) => '#' + id;
const nextId = () => line++;

// Helpers
const PERSON = nextId();          entities.push({id: PERSON, line: `IFCPERSON($,$,'ArquitAI',$,$,$,$,$);`});
const ORG = nextId();             entities.push({id: ORG, line: `IFCORGANIZATION($,'Estudio Damian Martinez',$,$,$);`});
const PERSON_ORG = nextId();      entities.push({id: PERSON_ORG, line: `IFCPERSONANDORGANIZATION(${ref(PERSON)},${ref(ORG)},$);`});
const APP = nextId();             entities.push({id: APP, line: `IFCAPPLICATION(${ref(ORG)},'1.0','ArquitAI v1.0','arquitai');`});
const OWNER_HIST = nextId();      entities.push({id: OWNER_HIST, line: `IFCOWNERHISTORY(${ref(PERSON_ORG)},${ref(APP)},$,.ADDED.,$,${ref(PERSON_ORG)},${ref(APP)},${Math.floor(now.getTime()/1000)});`});

const CART_ORIGIN = nextId();     entities.push({id: CART_ORIGIN, line: `IFCCARTESIANPOINT((0.,0.,0.));`});
const AXIS_PLACEMENT_3D = nextId(); entities.push({id: AXIS_PLACEMENT_3D, line: `IFCAXIS2PLACEMENT3D(${ref(CART_ORIGIN)},$,$);`});
const LOCAL_PLACEMENT = nextId(); entities.push({id: LOCAL_PLACEMENT, line: `IFCLOCALPLACEMENT($,${ref(AXIS_PLACEMENT_3D)});`});

const LENGTH_UNIT = nextId();     entities.push({id: LENGTH_UNIT, line: `IFCSIUNIT(*,.LENGTHUNIT.,$,.METRE.);`});
const AREA_UNIT = nextId();       entities.push({id: AREA_UNIT, line: `IFCSIUNIT(*,.AREAUNIT.,$,.SQUARE_METRE.);`});
const VOL_UNIT = nextId();        entities.push({id: VOL_UNIT, line: `IFCSIUNIT(*,.VOLUMEUNIT.,$,.CUBIC_METRE.);`});
const UNITS = nextId();           entities.push({id: UNITS, line: `IFCUNITASSIGNMENT((${ref(LENGTH_UNIT)},${ref(AREA_UNIT)},${ref(VOL_UNIT)}));`});

const REPR_CTX = nextId();        entities.push({id: REPR_CTX, line: `IFCGEOMETRICREPRESENTATIONCONTEXT($,'Model',3,1.0E-5,${ref(AXIS_PLACEMENT_3D)},$);`});

const PROJECT = nextId();         entities.push({id: PROJECT, line: `IFCPROJECT('${'P'+data.project_id.replace(/-/g,'').slice(0,20)}',${ref(OWNER_HIST)},'${projectName}','Reforma','${designTitle}','${projectName}',$,(${ref(REPR_CTX)}),${ref(UNITS)});`});

const SITE = nextId();            entities.push({id: SITE, line: `IFCSITE('${'S'+data.project_id.replace(/-/g,'').slice(0,20)}',${ref(OWNER_HIST)},'Site','${location}',$,${ref(LOCAL_PLACEMENT)},$,$,.ELEMENT.,$,$,$,$,$);`});
const BUILDING = nextId();        entities.push({id: BUILDING, line: `IFCBUILDING('${'B'+data.project_id.replace(/-/g,'').slice(0,20)}',${ref(OWNER_HIST)},'Edificio','${projectName}',$,${ref(LOCAL_PLACEMENT)},$,$,.ELEMENT.,$,$,$);`});
const STOREY = nextId();          entities.push({id: STOREY, line: `IFCBUILDINGSTOREY('${'L'+data.project_id.replace(/-/g,'').slice(0,20)}',${ref(OWNER_HIST)},'Planta','Piso unico',$,${ref(LOCAL_PLACEMENT)},$,$,.ELEMENT.,0.);`});

const spaceIds = [];
rooms.forEach((room, i) => {
  const SPACE = nextId();
  spaceIds.push(SPACE);
  entities.push({id: SPACE, line: `IFCSPACE('${'SP'+i+'_'+data.project_id.replace(/-/g,'').slice(0,16)}',${ref(OWNER_HIST)},'${escape(room)}','Estancia',$,${ref(LOCAL_PLACEMENT)},$,$,.ELEMENT.,.SPACE.,$);`});
});

// Aggregations: site contains building, building contains storey, storey contains spaces
const REL_SITE_PROJECT = nextId(); entities.push({id: REL_SITE_PROJECT, line: `IFCRELAGGREGATES('rsp${REL_SITE_PROJECT}',${ref(OWNER_HIST)},'Site Contained',$,${ref(PROJECT)},(${ref(SITE)}));`});
const REL_BLD_SITE = nextId();    entities.push({id: REL_BLD_SITE, line: `IFCRELAGGREGATES('rbs${REL_BLD_SITE}',${ref(OWNER_HIST)},'Building Contained',$,${ref(SITE)},(${ref(BUILDING)}));`});
const REL_STO_BLD = nextId();     entities.push({id: REL_STO_BLD, line: `IFCRELAGGREGATES('rsb${REL_STO_BLD}',${ref(OWNER_HIST)},'Storey Contained',$,${ref(BUILDING)},(${ref(STOREY)}));`});
if (spaceIds.length > 0) {
  const REL_SPC_STO = nextId();   entities.push({id: REL_SPC_STO, line: `IFCRELAGGREGATES('rsps${REL_SPC_STO}',${ref(OWNER_HIST)},'Spaces in Storey',$,${ref(STOREY)},(${spaceIds.map(ref).join(',')}));`});
}

// Materials
materials.forEach((m, i) => {
  const MAT = nextId();
  const matName = escape((m.name || m.category || 'Material') + (m.specification ? ' - ' + m.specification : ''));
  entities.push({id: MAT, line: `IFCMATERIAL('${matName}');`});
});

const body = entities.map(e => `#${e.id}=${e.line}`).join('\n');

const ifcContent = `ISO-10303-21;
HEADER;
FILE_DESCRIPTION(('ViewDefinition [CoordinationView_V2.0]'),'2;1');
FILE_NAME('${projectName}','${isoStamp}',('ArquitAI'),('Estudio Damian Martinez'),'IFC4 stub','ArquitAI v1.0','');
FILE_SCHEMA(('IFC4'));
ENDSEC;
DATA;
${body}
ENDSEC;
END-ISO-10303-21;
`;

const stamp = isoStamp.replace(/[-:T]/g, '').slice(0,15);
const filename = `${data.project_id.substring(0,8)}_${stamp}.ifc`;

return [{ json: {
  filename: filename,
  content: ifcContent,
  bytes: Buffer.byteLength(ifcContent, 'utf8'),
  spaces_count: spaceIds.length,
  materials_count: materials.length,
  project_id: data.project_id,
  project_name: data.project_name
}}];

